// frontend/src/components/LeanConnect.tsx
import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';

const API_URL = 'http://localhost:3001';

declare global {
    interface Window {
        Lean: any;
    }
}

interface LeanConnectProps {
    customerId: string;
    onSuccess: (entityId: string) => void;
    onError: (error: string) => void;
}

const LeanConnect: React.FC<LeanConnectProps> = ({ customerId, onSuccess, onError }) => {
    const [loading, setLoading] = useState(false);
    const [status, setStatus] = useState<string>('');
    const [showManualOverride, setShowManualOverride] = useState(false);
    const callbackRegistered = useRef(false);
    const connectionInProgress = useRef(false);
    const timeoutRef = useRef<NodeJS.Timeout | null>(null);

    // ============================================================
    // 1. REGISTER LEAN CALLBACK ONCE
    // ============================================================
    useEffect(() => {
        if (!callbackRegistered.current && window.Lean) {
            console.log('🔄 Registering Lean callback...');
            window.Lean.callback = (response: any) => {
                console.log('📨 Lean callback received:', response);
                setLoading(false);
                connectionInProgress.current = false;
                if (timeoutRef.current) {
                    clearTimeout(timeoutRef.current);
                    timeoutRef.current = null;
                }
                setShowManualOverride(false);

                if (response.status === 'SUCCESS') {
                    setStatus('✅ Bank connected successfully!');
                    onSuccess(response.entity_id || 'success');
                } else if (response.status === 'ERROR') {
                    setStatus('❌ Error: ' + response.message);
                    onError(response.message || 'Failed');
                } else if (response.status === 'CANCEL') {
                    setStatus('⏹️ Cancelled');
                    onError('Cancelled');
                }
            };
            callbackRegistered.current = true;
        }
    }, [onSuccess, onError]);

    // ============================================================
    // 2. CONNECT BANK
    // ============================================================
    const handleConnect = async () => {
        if (connectionInProgress.current || loading) {
            console.warn('⏳ Connection already in progress...');
            return;
        }

        connectionInProgress.current = true;
        setLoading(true);
        setStatus('🔐 Getting customer token...');
        setShowManualOverride(false);

        try {
            const tokenRes = await axios.get(`${API_URL}/api/lean/customer-token`, {
                params: { customerId }
            });

            if (!tokenRes.data.success) {
                throw new Error(tokenRes.data.error || 'Customer token failed');
            }

            const customerToken = tokenRes.data.customerToken;
            const appToken = '730a9f67-7149-49e5-988d-30200b8fa695';

            console.log('✅ Customer token received');

            window.Lean.connect({
                access_token: customerToken,
                app_token: appToken,
                customer_id: customerId,
                permissions: ['identity', 'accounts', 'balance', 'transactions'],
                sandbox: true,
                debug: true
            });

            setStatus('🔄 Waiting for bank authorization...');
            console.log('✅ Lean.connect() called, waiting for callback...');

            // 🔥 AUTO-FALLBACK: Show manual override after 15 seconds
            if (timeoutRef.current) {
                clearTimeout(timeoutRef.current);
            }
            timeoutRef.current = setTimeout(() => {
                console.warn('⏰ Callback not received after 15 seconds. Showing manual override.');
                setShowManualOverride(true);
                setStatus('⏳ Still waiting... Click "Skip & Connect" if you completed the bank flow.');
            }, 15000);

        } catch (error: any) {
            const msg = error.response?.data?.error || error.message || 'Connection failed';
            setStatus('❌ Error: ' + msg);
            onError(msg);
            setLoading(false);
            connectionInProgress.current = false;
            setShowManualOverride(false);
        }
    };

    // ============================================================
    // 3. MANUAL OVERRIDE (The "Skip" button)
    // ============================================================
    const handleManualOverride = () => {
        if (timeoutRef.current) {
            clearTimeout(timeoutRef.current);
            timeoutRef.current = null;
        }
        setStatus('✅ Bank connected manually (demo mode)');
        setShowManualOverride(false);
        setLoading(false);
        connectionInProgress.current = false;
        onSuccess('manual_entity');
    };

    // ============================================================
    // 4. CANCEL
    // ============================================================
    const handleCancel = () => {
        if (timeoutRef.current) {
            clearTimeout(timeoutRef.current);
            timeoutRef.current = null;
        }
        setStatus('⏹️ Cancelled');
        setShowManualOverride(false);
        setLoading(false);
        connectionInProgress.current = false;
        onError('Cancelled');
    };

    // ============================================================
    // 5. RENDER
    // ============================================================
    return (
        <div className="lean-connect" style={{ marginTop: 8 }}>
            <button
                onClick={handleConnect}
                disabled={loading}
                className="btn-connect"
                style={{
                    width: '100%',
                    padding: '12px',
                    background: loading ? '#a0aec0' : 'linear-gradient(135deg, #006a4e, #00875a)',
                    color: '#fff',
                    border: 'none',
                    borderRadius: '10px',
                    fontSize: '16px',
                    fontWeight: '600',
                    cursor: loading ? 'not-allowed' : 'pointer',
                    transition: 'transform 0.2s, box-shadow 0.2s',
                }}
            >
                {loading ? '⏳ Connecting...' : '🔗 Connect Bank Account'}
            </button>

            {status && (
                <p
                    style={{
                        marginTop: 8,
                        fontSize: 13,
                        color: status.includes('✅')
                            ? '#22543d'
                            : status.includes('❌') || status.includes('⏳')
                            ? '#9b2c2c'
                            : '#2b6cb0',
                    }}
                >
                    {status}
                </p>
            )}

            {/* Actions: Manual Override or Cancel */}
            {loading && (
                <div style={{ marginTop: 8, display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
                    {showManualOverride && (
                        <button
                            onClick={handleManualOverride}
                            style={{
                                padding: '8px 20px',
                                background: '#48bb78',
                                color: '#fff',
                                border: 'none',
                                borderRadius: '6px',
                                cursor: 'pointer',
                                fontSize: '14px',
                                fontWeight: '600',
                            }}
                        >
                            ⚡ Skip & Connect (Demo)
                        </button>
                    )}
                    <button
                        onClick={handleCancel}
                        style={{
                            padding: '8px 16px',
                            background: '#e53e3e',
                            color: '#fff',
                            border: 'none',
                            borderRadius: '6px',
                            cursor: 'pointer',
                            fontSize: '14px',
                        }}
                    >
                        Cancel
                    </button>
                </div>
            )}
        </div>
    );
};

export default LeanConnect;
